const markExactReservedInventorySold = `-- name: MarkExactReservedInventorySold :many
WITH eligible AS (
    SELECT inventory.id
    FROM order_inventory_items AS mapping
    JOIN inventory_items AS inventory ON inventory.id = mapping.inventory_item_id
    WHERE mapping.order_id = $1
      AND mapping.status = 'active'
      AND inventory.status = 'reserved'
      AND inventory.reserved_order_id = mapping.order_id
    ORDER BY inventory.id
    FOR UPDATE OF inventory
), exact_set AS (
    SELECT id
    FROM eligible
    WHERE (SELECT count(*) FROM eligible) = $2::integer
)
UPDATE inventory_items AS inventory
SET status = 'sold',
    reserved_order_id = NULL,
    reserved_until = NULL,
    sold_order_id = $1,
    version = inventory.version + 1
FROM exact_set
WHERE inventory.id = exact_set.id
RETURNING inventory.id
`

type MarkExactReservedInventorySoldParams struct {
	OrderID       pgtype.Int8 `db:"order_id" json:"order_id"`
	ExpectedCount int32       `db:"expected_count" json:"expected_count"`
}

func (q *Queries) MarkExactReservedInventorySold(ctx context.Context, arg MarkExactReservedInventorySoldParams) ([]int64, error) {
	rows, err := q.db.Query(ctx, markExactReservedInventorySold, arg.OrderID, arg.ExpectedCount)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []int64{}
	for rows.Next() {
		var id int64
		if err := rows.Scan(&id); err != nil {
			return nil, err
		}
		items = append(items, id)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

